function solve(nums) {
    let maxSum = 0;
    const n = nums.length;

    for (let i = 0; i <= n; i++) {
        for (let j = i; j <= n; j++) {
            // B is nums[i..j-1]
            let andB = ~0; // All bits set for initial AND
            const B = nums.slice(i, j);
            for (const num of B) {
                andB &= num;
            }
            if (B.length === 0) {
                andB = 0;
            }

            // A is nums[0..i-1], C is nums[j..n-1]
            const A = nums.slice(0, i);
            const C = nums.slice(j);

            let xorA = 0;
            for (const num of A) {
                xorA ^= num;
            }

            let xorC = 0;
            for (const num of C) {
                xorC ^= num;
            }

            const currentSum = xorA + andB + xorC;
            if (currentSum > maxSum) {
                maxSum = currentSum;
            }
        }
    }

    return maxSum;
}
